#include <openssl/md5.h>

void hash_password(char *password, unsigned char *hash) {
    MD5_CTX ctx;
    MD5_Init(&ctx);
    MD5_Update(&ctx, password, strlen(password)); // Noncompliant: MD5 is weak
    MD5_Final(hash, &ctx);
}

// Also noncompliant:
void hash_data_sha1(char *data, unsigned char *hash) {
    SHA1(data, strlen(data), hash); // Noncompliant: SHA1 is broken
}

compliant:
#include <openssl/sha.h>
#include <openssl/evp.h>

void hash_password_secure(char *password, unsigned char *hash) {
    SHA256_CTX ctx;
    SHA256_Init(&ctx);
    SHA256_Update(&ctx, password, strlen(password)); // Compliant: SHA256 is secure
    SHA256_Final(hash, &ctx);
}

// Even better - use EVP interface:
void hash_with_evp(char *data, unsigned char *hash) {
    EVP_MD_CTX *ctx = EVP_MD_CTX_new();
    EVP_DigestInit_ex(ctx, EVP_sha3_256(), NULL); // Compliant: SHA3-256
    EVP_DigestUpdate(ctx, data, strlen(data));
    unsigned int hash_len;
    EVP_DigestFinal_ex(ctx, hash, &hash_len);
    EVP_MD_CTX_free(ctx);
}
